void PrintNumber(uint16_t number)
{
	// Check max and min
	if (number > 9999)
	{
		number = 9999;
	}

	// Convert integer to bcd digits
	buffer[0] = number / 1000;
	buffer[1] = number % 1000 / 100;
	buffer[2] = number % 100 / 10;
	buffer[3] = number % 10;
}
